// Grab the name from the loop
const name = $('Loop Over Rows').item.json['Name'];

// Grab all config rows — each row is one question/field
const configRows = $input.all();

// Build a map of field_key -> question with [NAME] replaced
const fieldMap = {};
const questionLines = [];

for (const row of configRows) {
  const fieldKey = row.json['Field Key'];         // e.g. current_company
  const columnLetter = row.json['Column'];        // e.g. C
  const rawQuestion = row.json['Question Template']; // e.g. What company does [NAME] work for?

  if (!fieldKey || !rawQuestion) continue;

  // Replace [NAME] placeholder with actual name
  const hydrated = rawQuestion.replace(/\[NAME\]/gi, name);

  fieldMap[fieldKey] = {
    column: columnLetter,
    question: hydrated
  };

  questionLines.push(`- ${fieldKey}: ${hydrated}`);
}

// Build the JSON keys block for the prompt
const jsonKeys = Object.keys(fieldMap)
  .map(k => `  "${k}": ""`)
  .join(',\n');

// Build the final prompt
const prompt = `Research the following person: ${name}

Return ONLY a valid JSON object with exactly these keys, no explanation, no markdown, no citations:
{
${jsonKeys}
}

Answer each key using these questions:
${questionLines.join('\n')}

If you cannot find an answer for a field, use the string "Not found" as the value.`;

return [{
  json: {
    name: name,
    row_number: $('Loop Over Rows').item.json['row_number'],
    prompt: prompt,
    field_map: fieldMap,
    field_keys: Object.keys(fieldMap)
  }
}];

