// Get Perplexity raw response
let raw = '';
try {
  raw = $input.first().json.choices[0].message.content;
} catch (e) {
  throw new Error('Could not read Perplexity response: ' + e.message);
}

// Strip markdown fences if present
raw = raw.replace(/```json/gi, '').replace(/```/g, '').trim();

// Parse JSON
let parsed;
try {
  parsed = JSON.parse(raw);
} catch (e) {
  throw new Error('JSON parse failed. Raw response: ' + raw);
}

// Pull field map and metadata from Build Dynamic Prompt node
const fieldMap = $('Build Dynamic Prompt').item.json.field_map;
const fieldKeys = $('Build Dynamic Prompt').item.json.field_keys;
const name = $('Build Dynamic Prompt').item.json.name;
const rowNumber = $('Build Dynamic Prompt').item.json.row_number;

// Build the sheet update payload dynamically from field map
const sheetPayload = { row_number: rowNumber };
const notFoundFields = [];

for (const key of fieldKeys) {
  const value = parsed[key] || 'Not found';
  sheetPayload[key] = value;

  if (!parsed[key] || parsed[key].toLowerCase() === 'not found') {
    notFoundFields.push(key);
  }
}

return [{
  json: {
    ...sheetPayload,
    name: name,
    field_map: fieldMap,
    field_keys: fieldKeys,
    not_found_fields: notFoundFields,
    has_missing: notFoundFields.length > 0
  }
}];

// This node dynamically maps parsed field values back to their sheet columns
const input = $input.first().json;
const fieldMap = input.field_map;
const fieldKeys = input.field_keys;
const rowNumber = input.row_number;

const columnPayload = {
  row_number: rowNumber,
  Status: 'Done',
  'Error Log': ''
};

for (const key of fieldKeys) {
  const colHeader = fieldMap[key]?.column;
  const value = input[key] || 'Not found';
  if (colHeader) {
    columnPayload[colHeader] = value;
  }
}

return [{
  json: columnPayload
}];

